{
  "name": "crm-system-prototype",
  "version": "0.1.0",
  "description": "Prototype CRM System for managing customers, sales, support, and analytics.",
  "main": "server.js",
  "scripts": {
    "start": "node server.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "body-parser": "^1.20.2",
    "cors": "^2.8.5"
  },
  "engines": {
    "node": ">=14"
  },
  "keywords": ["crm", "prototype", "customer", "sales", "support"],
  "author": "Generated Prototype",
  "license": "MIT"
}

const express = require('express');
const bodyParser = require('body-parser');
const cors = require('cors');

const app = express();
const port = 3000;

app.use(cors());
app.use(bodyParser.json());
app.use(express.static('app'));

// In-memory data stores
let contacts = [];
let interactions = [];
let salesOpportunities = [];
let supportTickets = [];

// Helper to generate IDs
const generateId = () => Math.random().toString(36).substr(2, 9);

// Routes

// Contacts
app.get('/api/contacts', (req, res) => {
  res.json(contacts);
});

app.post('/api/contacts', (req, res) => {
  const contact = { id: generateId(), ...req.body };
  contacts.push(contact);
  res.status(201).json(contact);
});

app.put('/api/contacts/:id', (req, res) => {
  const id = req.params.id;
  const index = contacts.findIndex(c => c.id === id);
  if (index === -1) return res.status(404).json({ error: 'Contact not found' });
  contacts[index] = { ...contacts[index], ...req.body };
  res.json(contacts[index]);
});

app.delete('/api/contacts/:id', (req, res) => {
  const id = req.params.id;
  contacts = contacts.filter(c => c.id !== id);
  res.status(204).send();
});

// Interactions
app.get('/api/interactions', (req, res) => {
  res.json(interactions);
});

app.post('/api/interactions', (req, res) => {
  const interaction = { id: generateId(), ...req.body };
  interactions.push(interaction);
  res.status(201).json(interaction);
});

// Sales Opportunities
app.get('/api/sales', (req, res) => {
  res.json(salesOpportunities);
});

app.post('/api/sales', (req, res) => {
  const sale = { id: generateId(), ...req.body };
  salesOpportunities.push(sale);
  res.status(201).json(sale);
});

app.put('/api/sales/:id', (req, res) => {
  const id = req.params.id;
  const index = salesOpportunities.findIndex(s => s.id === id);
  if (index === -1) return res.status(404).json({ error: 'Sale not found' });
  salesOpportunities[index] = { ...salesOpportunities[index], ...req.body };
  res.json(salesOpportunities[index]);
});

// Support Tickets
app.get('/api/tickets', (req, res) => {
  res.json(supportTickets);
});

app.post('/api/tickets', (req, res) => {
  const ticket = { id: generateId(), status: 'open', ...req.body };
  supportTickets.push(ticket);
  res.status(201).json(ticket);
});

app.put('/api/tickets/:id', (req, res) => {
  const id = req.params.id;
  const index = supportTickets.findIndex(t => t.id === id);
  if (index === -1) return res.status(404).json({ error: 'Ticket not found' });
  supportTickets[index] = { ...supportTickets[index], ...req.body };
  res.json(supportTickets[index]);
});

// Simple Analytics Endpoint
app.get('/api/analytics', (req, res) => {
  const totalContacts = contacts.length;
  const totalInteractions = interactions.length;
  const openTickets = supportTickets.filter(t => t.status === 'open').length;
  const closedTickets = supportTickets.filter(t => t.status === 'closed').length;
  const salesCount = salesOpportunities.length;

  res.json({
    totalContacts,
    totalInteractions,
    openTickets,
    closedTickets,
    salesCount
  });
});

// Serve frontend
app.get('/', (req, res) => {
  res.sendFile(__dirname + '/app/index.html');
});

app.listen(port, () => {
  console.log(`CRM System prototype listening at http://localhost:${port}`);
});
